import requests

def make_authenticated_request(url: str, token: str, method: str = 'GET', json_data: dict = None, params: dict = None, **kwargs) -> requests.Response:
    headers = {
        'Authorization': f'Bearer {token}'
    }
    if json_data is not None:
        headers['Content-Type'] = 'application/json'

    response = requests.request(
        method=method.upper(),
        url=url,
        headers=headers,
        json=json_data,
        params=params,
        **kwargs
    )
    return response
